SELECT NVL(MAX(group_id), 0) 
FROM tbl_msg 
WHERE room_id = #{room_id}

SELECT * FROM (
    SELECT m.*, ROW_NUMBER() OVER (ORDER BY m.msg_id DESC) rn
    FROM tbl_msg m
    WHERE m.room_id = #{room_id}
      AND m.is_active = 'Y'
)
WHERE rn > #{offset} AND rn <= #{offset} + #{size}
ORDER BY msg_id ASC
